feather.replace();

let entreprise;
let donneesEntreprise = {};
let question_oui = 0;
let question_non = 0;
let question_partiel = 0;
let question_non_applicable = 0;
let score = 0;

// Fonction utilitaire pour calculer les stats
function calculateStats() {
    return {
        question_oui,
        question_non,
        question_partiel,
        question_non_applicable
    };
}

// Frappe ready
frappe.ready(() => {
    // Étape 1: Récupérer l'entreprise de l'utilisateur connecté
    frappe.call('frappe.client.get', {
        doctype: 'User',
        name: frappe.session.user,
    }).then((response) => {
        entreprise = response.message.entreprise;

        if (!entreprise) {
            frappe.msgprint('Aucune entreprise associée à cet utilisateur.');
            return;
        }


        // Doctypes à récupérer
        const doctypes = [
            { name: 'customer_grc', field: 'entreprise' },
            { name: 'department_grc', field: 'entreprise' },
            { name: 'service_grc', field: 'entreprise' },
            { name: 'file_processing_grc', field: 'entreprise' },
            { name: 'action_plan_grc', field: 'entreprise' },
            { name: 'violation_grc', field: 'entreprise' },
            { name: 'Point_de_controle', field: 'entreprise' },
            { name: 'Niveau_avancement_service', field: 'entreprise' },
            { name: 'question_score', field: 'entreprise' },
            { name: 'make_right_grc', field: 'entreprise' }
        ];

        // Récupération des données de tous les doctypes
        Promise.all(doctypes.map((doctype) =>
            frappe.call('frappe.client.get_list', {
                doctype: doctype.name,
                filters: [[doctype.field, 'like', `%${entreprise}%`]],
                fields: ['*'],
            }).then((res) => {
                donneesEntreprise[doctype.name] = res.message;
            }).catch(err => {
                console.warn(`Erreur pour ${doctype.name} :`, err.message);
            })
        )).then(() => {

            // Calcul des scores à partir de question_score
            if (donneesEntreprise.question_score?.length) {
                Object.entries(donneesEntreprise.question_score[0]).forEach(([question, value]) => {
                    switch (value) {
                        case "Oui":
                            question_oui++;
                            break;
                        case "Non":
                            question_non++;
                            break;
                        case "Partiel":
                            question_partiel++;
                            break;
                        case "Non/applicable":
                            question_non_applicable++;
                            break;
                    }
                });
            }

            // Calcul du score global
            score = Math.round(((question_oui + (question_partiel * 0.5)) / 20) * 100);

            // Affichage des logs
            console.log("Données complètes de l'entreprise:", donneesEntreprise);
            console.log("Oui:", question_oui);
            console.log("Non:", question_non);
            console.log("Partiel:", question_partiel);
            console.log("Non applicable:", question_non_applicable);
            console.log("Score:", score);

            // MAJ graphique
            updateCircularProgress(score);
            updateCardContent(donneesEntreprise);

            // Init autres composants
            renderControlsList();
            setupFilterButtons();
            setupExportPDF();

        });
    });
});

// Met à jour le graphique circulaire de score
function updateCircularProgress(score) {
    const circle = document.getElementById('progress-circle');
    const offset = 628 - (628 * score / 100);
    circle.style.strokeDashoffset = offset;
    document.getElementById('compliance-score').textContent = `${score}%`;

    const stats = calculateStats();
    document.getElementById('conforme-count').textContent = stats.question_oui;
    document.getElementById('partiel-count').textContent = stats.question_partiel;
    document.getElementById('non-conforme-count').textContent = stats.question_non;
    document.getElementById('non-applicable-count').textContent = stats.question_non_applicable;
}

function updateCardContent(data){
    document.getElementById('violation-count').textContent = data.violation_grc.length;
    document.getElementById('action-plan-count').textContent = data.action_plan_grc.length;
    document.getElementById('make-right-count').textContent = data.make_right_grc.length;
    document.getElementById('file-processing-count').textContent = data.file_processing_grc.length;
}

// Affiche un tooltip sur la heatmap
function showTooltip(event) {
    const tooltip = document.getElementById('heatmap-tooltip');
    const cell = event.currentTarget;

    document.getElementById('tooltip-service').textContent = cell.dataset.service;
    document.getElementById('tooltip-risk').textContent = cell.dataset.risk;
    document.getElementById('tooltip-count').textContent = `${cell.dataset.count} incidents`;

    tooltip.style.display = 'block';
    tooltip.style.left = `${event.pageX + 10}px`;
    tooltip.style.top = `${event.pageY + 10}px`;

    cell.addEventListener('mouseout', () => {
        tooltip.style.display = 'none';
    });
}

function toggleSidebar(open) {
    const sidebar = document.getElementById('sidebar');
    const openBtn = document.getElementById('openSidebarBtn');
    const closeBtn = document.getElementById('closeSidebarBtn');

    if (open) {
        sidebar.classList.remove('-translate-x-full');
        openBtn.classList.add('hidden');
        closeBtn.classList.remove('hidden');
    } else {
        sidebar.classList.add('-translate-x-full');
        closeBtn.classList.add('hidden');
        openBtn.classList.remove('hidden');
    }
}

    function logout() {
        frappe.call({
            method: 'logout',
            callback: function () {
                window.location.href = '/login';
            }
        });
    }

    // Recharge les icônes après chargement
    document.addEventListener('DOMContentLoaded', () => {
        feather.replace();
    });

