    const recordElements = document.querySelectorAll('.record-item');
    const fileProcessingGRC = [];
    
    recordElements.forEach(el => {
        fileProcessingGRC.push({
            name: el.dataset.id,
            service_concerner: el.querySelector('p:nth-child(2) span').textContent,
            fonction: el.querySelector('p:nth-child(4) span').textContent,
            nom: el.querySelector('h3').textContent,
