    const nextPageFooterBtn = document.getElementById('next-page-footer');
    const pageNumbers = document.getElementById('page-numbers');
    const pageNumbersFooter = document.getElementById('page-numbers-footer');
    const noResults = document.getElementById('no-results');
    const activeFilters = document.getElementById('active-filters');
    const currentView = document.getElementById('current-view');

    // State
    let currentPage = 1;
    const recordsPerPage = 4;
    let filteredRecords = [...fileProcessingGRC];
    let activeFilterCount = 0;

    // Initialize view
    function initializeView() {
        renderRecords();
        renderPagination();
        updateActiveFilters();
    }

    // Render records
    function renderRecords() {
        const startIndex = (currentPage - 1) * recordsPerPage;
        const endIndex = startIndex + recordsPerPage;
        const currentRecords = filteredRecords.slice(startIndex, endIndex);
        
        // Hide all records
        document.querySelectorAll('.record-item').forEach(el => {
            el.classList.add('hidden');
        });
        
        if (currentRecords.length === 0) {
            noResults.classList.remove('hidden');
            return;
        }
        
        noResults.classList.add('hidden');
        
        // Show only current page records
        currentRecords.forEach(rec => {
            const recordEl = document.querySelector(`.record-item[data-id="${rec.name}"]`);
            if (recordEl) {
                recordEl.classList.remove('hidden');
            }
        });
    }

    // Render pagination
    function renderPagination() {
        const totalPages = Math.ceil(filteredRecords.length / recordsPerPage);
        
        pageNumbers.innerHTML = '';
        pageNumbersFooter.innerHTML = '';
        
        // Previous buttons
        prevPageBtn.disabled = currentPage === 1;
        prevPageFooterBtn.disabled = currentPage === 1;
        
        // Next buttons
        nextPageBtn.disabled = currentPage === totalPages;
        nextPageFooterBtn.disabled = currentPage === totalPages;
        
        // Page numbers
        for (let i = 1; i <= totalPages; i++) {
            const pageBtn = document.createElement('button');
            pageBtn.className = `page-btn ${i === currentPage ? 'active' : ''}`;
            pageBtn.textContent = i;
            pageBtn.addEventListener('click', () => {
                currentPage = i;
                renderRecords();
                renderPagination();
            });
            
            const pageBtnFooter = pageBtn.cloneNode(true);
            pageBtnFooter.addEventListener('click', () => {
                currentPage = i;
                renderRecords();
                renderPagination();
            });
            
            pageNumbers.appendChild(pageBtn);
            pageNumbersFooter.appendChild(pageBtnFooter);
        }
    }

    // Apply filters
    function applyFilters() {
        const serviceVal = serviceFilter.value;
        const statusVal = statusFilter.value;
        const searchVal = searchInput.value.toLowerCase();
        
        filteredRecords = fileProcessingGRC.filter(rec => {
            const matchesService = serviceVal === 'all' || 
                rec.service_concerner.toLowerCase().includes(serviceVal);
            
            const matchesStatus = statusVal === 'all' || 
                rec.statut_de_la_personne_concerner.toLowerCase().includes(statusVal);
            
            const matchesSearch = searchVal === '' || 
                rec.nom.toLowerCase().includes(searchVal) || 
                rec.email.toLowerCase().includes(searchVal) || 
                rec.fonction.toLowerCase().includes(searchVal);
            
            return matchesService && matchesStatus && matchesSearch;
        });
        
        // Count active filters
        activeFilterCount = 0;
        if (serviceVal !== 'all') activeFilterCount++;
        if (statusVal !== 'all') activeFilterCount++;
        if (searchVal !== '') activeFilterCount++;
        
        currentPage = 1;
        renderRecords();
        renderPagination();
        updateActiveFilters();
    }

    // Reset filters
    function resetFilters() {
        serviceFilter.value = 'all';
        statusFilter.value = 'all';
        searchInput.value = '';
        applyFilters();
    }

    // Open details modal
    function openDetailsModal(record) {
        document.getElementById('detail-nom').textContent = record.nom;
        document.getElementById('detail-email').textContent = record.email;
        document.getElementById('detail-service').textContent = record.service_concerner;
        document.getElementById('detail-status').textContent = record.statut_de_la_personne_concerner;
        document.getElementById('detail-fonction').textContent = record.fonction;
        document.getElementById('detail-finalite').textContent = record.finalité;
        document.getElementById('detail-base').textContent = record.base_légal_de_traitement;
        document.getElementById('detail-categorie').textContent = record.catégorie_de_donnée;
        document.getElementById('detail-duree').textContent = record.durée_de_conservation;
        document.getElementById('detail-mesures').textContent = record.mesure_de_sécurité;
        
        detailModal.classList.add('active');
        document.body.style.overflow = 'hidden';
    }

    // Close details modal
    function closeDetailsModal() {
        detailModal.classList.remove('active');
        document.body.style.overflow = 'auto';
    }

    // Update active filters display
    function updateActiveFilters() {
        activeFilters.textContent = activeFilterCount;
    }

    // Switch to card view
    function switchToCardView() {
        recordsContainer.classList.remove('list');
        recordsContainer.classList.add('grid', 'grid-cols-1', 'sm:grid-cols-2', 'md:grid-cols-3');
        cardViewBtn.classList.add('bg-blue-100', 'text-blue-600');
        listViewBtn.classList.remove('bg-blue-100', 'text-blue-600');
        listViewBtn.classList.add('bg-gray-100', 'text-gray-600');
        currentView.textContent = 'Grille';
    }

    // Switch to list view
    function switchToListView() {
        recordsContainer.classList.remove('grid', 'grid-cols-1', 'sm:grid-cols-2', 'md:grid-cols-3');
        recordsContainer.classList.add('list');
        listViewBtn.classList.add('bg-blue-100', 'text-blue-600');
        cardViewBtn.classList.remove('bg-blue-100', 'text-blue-600');
        cardViewBtn.classList.add('bg-gray-100', 'text-gray-600');
        currentView.textContent = 'Liste';
    }

    // Add event listeners to existing detail buttons
    document.querySelectorAll('.open-details').forEach(button => {
        button.addEventListener('click', function() {
            const recordId = this.closest('.record-item').dataset.id;
            const record = fileProcessingGRC.find(rec => rec.name === recordId);
            if (record) openDetailsModal(record);
        });
    });

    // Event Listeners
    applyBtn.addEventListener('click', applyFilters);
    resetBtn.addEventListener('click', resetFilters);
    searchInput.addEventListener('input', applyFilters);
    
    cardViewBtn.addEventListener('click', switchToCardView);
    listViewBtn.addEventListener('click', switchToListView);
    
    modalClose.addEventListener('click', closeDetailsModal);
    detailModal.addEventListener('click', (e) => {
        if (e.target === detailModal) {
            closeDetailsModal();
        }
    });
    
    prevPageBtn.addEventListener('click', () => {
        if (currentPage > 1) {
            currentPage--;
            renderRecords();
            renderPagination();
        }
    });
    
    nextPageBtn.addEventListener('click', () => {
        if (currentPage < Math.ceil(filteredRecords.length / recordsPerPage)) {
            currentPage++;
            renderRecords();
            renderPagination();
        }
    });
    
    prevPageFooterBtn.addEventListener('click', () => {
        if (currentPage > 1) {
            currentPage--;
            renderRecords();
            renderPagination();
        }
    });
    
    nextPageFooterBtn.addEventListener('click', () => {
        if (currentPage < Math.ceil(filteredRecords.length / recordsPerPage)) {
            currentPage++;
            renderRecords();
            renderPagination();
        }
    });
    
    // Initialize
    switchToCardView();
    renderPagination();
    updateActiveFilters();
});



