                control.history.forEach(item => {
                    const historyItem = document.createElement('div');
                    historyItem.className = 'border-l-2 pl-4 py-1';
                    
                    let statusColor = '';
                    switch(item.status) {
                        case 'conforme':
                            statusColor = 'border-green-500';
                            break;
                        case 'partiel':
                            statusColor = 'border-yellow-500';
                            break;
                        case 'non-conforme':
                            statusColor = 'border-red-500';
                            break;
                        default:
                            statusColor = 'border-gray-400';
                    }
                    
                    historyItem.classList.add(statusColor);
                    
                    historyItem.innerHTML = `
                        <div class="flex justify-between items-center">
                            <span class="text-sm font-medium">${item.date}</span>
                            <span class="text-xs px-2 py-0.5 rounded-full ${statusColor.replace('border', 'bg')} ${statusColor.replace('border', 'text')}">${item.status}</span>
                        </div>
                        <p class="text-sm text-gray-600 mt-1">${item.comment}</p>
                    `;
                    
                    historyList.appendChild(historyItem);
                });
            }
            
            // Show overlay
            document.getElementById('overlay-panel').classList.add('active');
            document.getElementById('overlay-backdrop').classList.add('active');
            
            // Close button
            document.querySelector('.close-overlay').addEventListener('click', closeControlDetails);
            document.getElementById('overlay-backdrop').addEventListener('click', closeControlDetails);
        }

        // Close control details
        function closeControlDetails() {
            document.getElementById('overlay-panel').classList.remove('active');
            document.getElementById('overlay-backdrop').classList.remove('active');
        }

        // Filter controls
        function setupFilterButtons() {
            document.querySelectorAll('.filter-btn').forEach(btn => {
                btn.addEventListener('click', () => {
                    // Remove active class from all buttons
                    document.querySelectorAll('.filter-btn').forEach(b => {
                        b.classList.remove('bg-blue-600', 'text-white');
                        if (b.dataset.status === 'conforme') b.classList.add('bg-green-100', 'text-green-800');
                        if (b.dataset.status === 'partiel') b.classList.add('bg-yellow-100', 'text-yellow-800');
                        if (b.dataset.status === 'non-conforme') b.classList.add('bg-red-100', 'text-red-800');
                        if (b.dataset.status === 'non-evalue') b.classList.add('bg-gray-100', 'text-gray-800');
                        if (b.dataset.status === 'all') b.classList.add('bg-gray-100', 'text-gray-800');
                    });
                    
                    // Add active class to clicked button
                    if (btn.dataset.status === 'all') {
                        btn.classList.add('bg-blue-600', 'text-white');
                        btn.classList.remove('bg-gray-100', 'text-gray-800');
                    } else {
                        btn.classList.add('bg-blue-600', 'text-white');
                    }
                    
                    renderControlsList(btn.dataset.status);
                });
            });
        }

        // Export to PDF
        function setupExportPDF() {
            document.getElementById('export-pdf').addEventListener('click', () => {
                // In a real app, we would use jsPDF to generate a PDF
                alert('Export PDF fonctionnalité serait implémentée ici avec jsPDF');
            });
        }

        // Initialize
        document.addEventListener('DOMContentLoaded', () => {
            const stats = calculateStats();
            updateCircularProgress(stats.score);
            renderControlsList();
            setupFilterButtons();
            setupExportPDF();
            
            // Set first filter button as active
            document.querySelector('.filter-btn[data-status="all"]').classList.add('bg-blue-600', 'text-white');
            document.querySelector('.filter-btn[data-status="all"]').classList.remove('bg-gray-100', 'text-gray-800');
        });
        
        
        
        function toggleSidebar(open) {
    const sidebar = document.getElementById('sidebar');
    const openBtn = document.getElementById('openSidebarBtn');
    const closeBtn = document.getElementById('closeSidebarBtn');

    if (open) {
        sidebar.classList.remove('-translate-x-full');
        openBtn.classList.add('hidden');
        closeBtn.classList.remove('hidden');
    } else {
        sidebar.classList.add('-translate-x-full');
        closeBtn.classList.add('hidden');
        openBtn.classList.remove('hidden');
    }
}

